import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./ExpenseUI.css";

function AddTravel({ employee }) {
  const navigate = useNavigate();

  const empId = employee?.empId || employee?.empld;

  const [form, setForm] = useState({
    travel_date: "",
    location_from: "",
    location_to: "",
    purpose: "",
    mode_of_travel: "",
    amount: "",
  });

  const saveTravel = async () => {
    try {
      await fetch("https://prasa-app-yde3.onrender.com/travel-expenses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, empId }),
      });

      alert("Travel Expense Added!");

      setForm({
        travel_date: "",
        location_from: "",
        location_to: "",
        purpose: "",
        mode_of_travel: "",
        amount: "",
      });
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div className="expense-container">

      <div className="back-btn" onClick={() => navigate("/addnew")}>← Back</div>

      <h2 className="page-title">Travel Expense</h2>

      <div className="expense-card">

        <div className="grid-3">

          <input
            type="date"
            value={form.travel_date}
            onChange={(e) => setForm({ ...form, travel_date: e.target.value })}
            className="input-box"
          />

          <input
            type="text"
            placeholder="From"
            value={form.location_from}
            onChange={(e) => setForm({ ...form, location_from: e.target.value })}
            className="input-box"
          />

          <input
            type="text"
            placeholder="To"
            value={form.location_to}
            onChange={(e) => setForm({ ...form, location_to: e.target.value })}
            className="input-box"
          />

          <input
            type="text"
            placeholder="Purpose"
            value={form.purpose}
            onChange={(e) => setForm({ ...form, purpose: e.target.value })}
            className="input-box"
          />

          <input
            type="text"
            placeholder="Mode of Travel"
            value={form.mode_of_travel}
            onChange={(e) => setForm({ ...form, mode_of_travel: e.target.value })}
            className="input-box"
          />

          <input
            type="number"
            placeholder="Amount"
            value={form.amount}
            onChange={(e) => setForm({ ...form, amount: e.target.value })}
            className="input-box"
          />
        </div>

        <button className="save-btn" onClick={saveTravel}>
          Save Travel Expense
        </button>
      </div>
    </div>
  );
}

export default AddTravel;
